import be.schaubroeck.lpb.rkm.rekenmotor.keys.RekenPatronaalPriveRszKey;
import be.schaubroeck.lpb.rkm.rekenmotor.keys.RekenPatronaalRszKey;
import be.schaubroeck.lpb.rkm.rekenmotor.keys.RekenRszKey;
import be.schaubroeck.lpb.rkm.rekenmotor.rsz.AbstractBijdragePercentages;
import be.schaubroeck.lpb.rkm.rekenmotor.rsz.AsbestfondsManager;
import be.schaubroeck.lpb.rkm.rekenmotor.rsz.dmfa.bijdrage.BijdragePensioenDmfa;
import be.schaubroeck.lpb.rkm.rekenmotor.rsz.dmfa.bijdrage.PatronaleBijdragePensioenDmfa;
import be.schaubroeck.lpb.rkm.rekenmotor.rsz.dmfa.bijdrage.WinstPremie;
import be.schaubroeck.lpb.rkm.rekenmotor.rsz.dmfa.bijdrage.patronaal.BijdrageFondsenBestaanszekerheidArbeiders;
import be.schaubroeck.lpb.rkm.rekenmotor.rsz.dmfa.bijdrage.patronaal.BijdrageFondsenBestaanszekerheidBedienden;
import be.schaubroeck.lpb.rkm.rekenmotor.rsz.dmfa.bijdrage.patronaal.BijdrageFso;
import be.schaubroeck.lpb.rkm.rekenmotor.rsz.dmfa.bijdrage.patronaal.BijdrageFsoFactory;
import be.schaubroeck.lpb.rkm.rekenmotor.rsz.dmfa.bijdrage.patronaal.BijdrageSectoraalPensioenfondsArbeiders;
import be.schaubroeck.lpb.rkm.rekenmotor.rsz.dmfa.bijdrage.patronaal.BijdrageSectoraalPensioenfondsBedienden;
import be.schaubroeck.lpb.rkm.rekenmotor.rsz.dmfa.bijdrage.patronaal.BijdrageVakantieRegelingPrive;
import be.schaubroeck.lpb.rkm.rekenmotor.rsz.dmfa.bijdrage.patronaal.BijzondereBijdrageArbeidsongevallen;
import be.schaubroeck.lpb.rkm.rekenmotor.rsz.dmfa.bijdrage.patronaal.BijzondereBijdrageAsbestfonds;
import be.schaubroeck.lpb.rkm.rekenmotor.rsz.dmfa.bijdrage.patronaal.TijdelijkeWerkloosheid;
import be.schaubroeck.lpb.rkm.rekenmotor.rsz.dmfa.bijdrage.patronaal.VerbrekingsvergoedingenSluitingsfonds;
import be.schaubroeck.lpb.rkm.rekenmotor.rsz.dmfa.bijdrage.patronaal.WerkgelegenheidEnVorming;
import be.schaubroeck.lpb.rkm.rekenmotor.util.ConstantManager;
import be.schaubroeck.lpb.rkm.rekenmotor.util.RegulManager;
import be.schaubroeck.lpb.tools.APKConstant2;
import be.schaubroeck.lpb.tools.enumtypes.DmfapplWnkengetal;
import be.schaubroeck.lpb.tools.enumtypes.Konstanten;
import be.schaubroeck.lpb.tools.enumtypes.Pensioenstelsel;
import be.schaubroeck.lpb.tools.enumtypes.WerkgeversCategorie;
import be.schaubroeck.lpb.tools.rsz.CategorieKengetalStatuutPensioenstelsel;
import be.schaubroeck.lpb.tools.rsz.dmfa.CategorieKengetalStatuutPensioenstelselDmfa;
import be.schaubroeck.lpb.tools.service.APKConstant2Service;
import be.schaubroeck.lpb.tools.service.DmfaVerminderingsPercentageService;
import be.schaubroeck.lpb.tools.service.DmfapplBasisBijdrageService;
import be.schaubroeck.lpb.tools.service.RszConstantService;
import lombok.Setter;
import org.joda.time.LocalDate;

import java.math.BigDecimal;

@Setter
public class DmfaBijdragePercentages extends AbstractBijdragePercentages {

    private final APKConstant2Service apkConstant2Service;
    private final ConstantManager constantManager;

    private BijdrageFso bepaalPercentagePatronaleBijdrageFso;
    private BijdrageFso bepaalPercentagePatronaleBijdrageFsoNietCommercieel;
    private BijdrageFondsenBestaanszekerheidArbeiders bijdrageFondsenBestaanszekerheidArbeiders;
    private BijdrageFondsenBestaanszekerheidBedienden bijdrageFondsenBestaanszekerheidBedienden;
    private BijdrageSectoraalPensioenfondsArbeiders bijdrageSectoraalPensioenfondsArbeiders;
    private BijdrageSectoraalPensioenfondsBedienden bijdrageSectoraalPensioenfondsBedienden;
    private WerkgelegenheidEnVorming werkgelegenheidEnVorming;
    private VerbrekingsvergoedingenSluitingsfonds verbrekingsvergoedingenSluitingsfonds;
    private TijdelijkeWerkloosheid tijdelijkeWerkloosheid;
    private BijdragePensioenDmfa bijdragePensioen;
    private PatronaleBijdragePensioenDmfa patronaleBijdragePensioen;
    private WinstPremie winstPremie;
    private BijdrageVakantieRegelingPrive bijdrageVakantieRegelingPrive;
    private BijzondereBijdrageArbeidsongevallen bijzondereBijdrageArbeidsongevallen;
    private BijzondereBijdrageAsbestfonds bijzondereBijdrageAsbestfonds;

    public DmfaBijdragePercentages(
            ConstantManager constantManager,
            RegulManager regulManager,
            RszConstantService rszConstantService,
            APKConstant2Service apkConstant2Service,
            DmfapplBasisBijdrageService dmfapplBasisBijdrageService,
            DmfaVerminderingsPercentageService dmfaVerminderingsPercentageService,
            RekenTijd rekenTijd) {
        super(constantManager, regulManager, rszConstantService, dmfapplBasisBijdrageService, dmfaVerminderingsPercentageService, new IsPool2TerDmfa(constantManager),
                new AsbestfondsManager(constantManager), rekenTijd);
        this.apkConstant2Service = apkConstant2Service;
        this.constantManager = constantManager;

        BijdrageFsoFactory bijdrageFsoFactory = new BijdrageFsoFactory(rszConstantService);
        this.bepaalPercentagePatronaleBijdrageFso = bijdrageFsoFactory.createGewoon();
        this.bepaalPercentagePatronaleBijdrageFsoNietCommercieel = bijdrageFsoFactory.createNietCommercieel();

        this.bijdrageFondsenBestaanszekerheidArbeiders = new BijdrageFondsenBestaanszekerheidArbeiders(rszConstantService);
        this.bijdrageFondsenBestaanszekerheidBedienden = new BijdrageFondsenBestaanszekerheidBedienden(rszConstantService);


        this.bijdrageSectoraalPensioenfondsArbeiders = new BijdrageSectoraalPensioenfondsArbeiders(rszConstantService, constantManager, rekenTijd);

        this.bijdrageSectoraalPensioenfondsBedienden = new BijdrageSectoraalPensioenfondsBedienden(rszConstantService, constantManager);
        this.tijdelijkeWerkloosheid = new TijdelijkeWerkloosheid(rszConstantService);
        this.verbrekingsvergoedingenSluitingsfonds = new VerbrekingsvergoedingenSluitingsfonds(rszConstantService, regulManager);
        this.werkgelegenheidEnVorming = new WerkgelegenheidEnVorming(rszConstantService);

        this.bijdragePensioen = new BijdragePensioenDmfa(rszConstantService, regulManager);
        this.patronaleBijdragePensioen = new PatronaleBijdragePensioenDmfa(rszConstantService, regulManager);
        this.winstPremie = new WinstPremie(rekenRszConstantService);

        this.bijdrageVakantieRegelingPrive = new BijdrageVakantieRegelingPrive(rekenRszConstantService);
        this.bijzondereBijdrageArbeidsongevallen = new BijzondereBijdrageArbeidsongevallen(rekenRszConstantService);
        this.bijzondereBijdrageAsbestfonds = new BijzondereBijdrageAsbestfonds(rekenRszConstantService);
    }

    @Override
    public BigDecimal getInhoudingBijdragePensioen(SleutelGegevens gegevens, LocalDate zoekDatum) {
        return bijdragePensioen.getPercentage(gegevens, zoekDatum);
    }

    @Override
    public BigDecimal getPatronaleBijdragePensioen(SleutelGegevens gegevens, LocalDate zoekDatum) {
        return patronaleBijdragePensioen.getPercentage(gegevens, zoekDatum);
    }

    @Override
    public BigDecimal bepaal(ContextKey bijdrageKey, SleutelGegevens gegevens, LocalDate zoekDatum) {
        if (bijdrageKey == RekenPatronaalPriveRszKey.PATRONALE_BIJDRAGE_FONDS_SLUITING_ONDERNEMING_KEY) {//810
            return bepaalPercentagePatronaleBijdrageFso.getPercentage(gegevens, zoekDatum);
        } else if (bijdrageKey == RekenPatronaalPriveRszKey.PATRONALE_BIJDRAGE_FSO_NIET_COMMERCIELE_WERKGEVERS_KEY) {//811
            return bepaalPercentagePatronaleBijdrageFsoNietCommercieel.getPercentage(gegevens, zoekDatum);
        } else if (bijdrageKey == RekenPatronaalPriveRszKey.PATRONALE_BIJDRAGE_VERBREKINGSVERGOEDINGEN_SLUITINGSFONDS_KEY) {//812
            return verbrekingsvergoedingenSluitingsfonds.getPercentage(gegevens, zoekDatum);
        } else if (bijdrageKey == RekenPatronaalPriveRszKey.PATRONALE_BIJDRAGE_FONDSEN_BESTAANSZEKERHEID_ARBEIDERS_KEY) {//820
            return bijdrageFondsenBestaanszekerheidArbeiders.getPercentage(gegevens, zoekDatum);
        } else if (bijdrageKey == RekenPatronaalPriveRszKey.PATRONALE_BIJDRAGE_SECTORAAL_PENSIOENFONDS_ARBEIDERS_KEY) {//825
            return bijdrageSectoraalPensioenfondsArbeiders.getPercentage(gegevens, zoekDatum);
        } else if (bijdrageKey == RekenPatronaalPriveRszKey.PATRONALE_BIJDRAGE_FONDSEN_BESTAANSZEKERHEID_BEDIENDEN_KEY) {//830
            return bijdrageFondsenBestaanszekerheidBedienden.getPercentage(gegevens, zoekDatum);
        } else if (bijdrageKey == RekenPatronaalPriveRszKey.PATRONALE_BIJDRAGE_SECTORAAL_PENSIOENFONDS_BEDIENDEN_KEY) {//835
            return bijdrageSectoraalPensioenfondsBedienden.getPercentage(gegevens, zoekDatum);
        } else if (bijdrageKey == RekenPatronaalPriveRszKey.PATRONALE_BIJDRAGE_WERKGELEGENHEID_EN_VORMING_KEY) {//852
            return werkgelegenheidEnVorming.getPercentage(gegevens, zoekDatum);
        } else if (bijdrageKey == RekenPatronaalPriveRszKey.PATRONALE_BIJDRAGE_TIJDELIJKE_WERKLOOSHEID_KEY) {//859
            return tijdelijkeWerkloosheid.getPercentage(gegevens, zoekDatum);
        } else if (bijdrageKey == RekenRszKey.BIJDRAGE_WINST_PREMIE_KEY) {
            return winstPremie.getPercentage(gegevens, zoekDatum);
        } else if (bijdrageKey == RekenPatronaalPriveRszKey.PATRONALE_BIJDRAGE_VAKREG_PRIVESECTOR_KEY) {
            return bijdrageVakantieRegelingPrive.getPercentage(gegevens, zoekDatum);
        } else if (bijdrageKey == RekenPatronaalRszKey.PATRONALE_BIJZONDERE_BIJDRAGE_ARBEIDSONGEVALLEN) {
            return bijzondereBijdrageArbeidsongevallen.getPercentage(gegevens, zoekDatum);
        } else if (bijdrageKey == RekenPatronaalRszKey.PATRONALE_BIJZONDERE_BIJDRAGE_ASBESTFONDS) {
            return bijzondereBijdrageAsbestfonds.getPercentage(gegevens, zoekDatum);
        } else {
            return super.bepaal(bijdrageKey, gegevens, zoekDatum);
        }
    }

    @Override
    protected CategorieKengetalStatuutPensioenstelsel getCategorieKengetalStatuutPensioenstelsel(SleutelGegevens gegevens) {
        return new CategorieKengetalStatuutPensioenstelselDmfa(gegevens.getWerkgeversCategorie(), gegevens.getWerknemersKengetal(), gegevens.getStatuutDmfappl(),
                gegevens.getPensioenStelsel());
    }

    @Override
    public BigDecimal getInhoudingPensioenVastbenoemdenApk(SleutelGegevens gegevens, LocalDate zoekDatum) {
        APKConstant2 apkConstant = apkConstant2Service.getByKey(gegevens.getPensioenStelsel(), zoekDatum);

        BigDecimal inhoudingPercentage = (apkConstant != null) ? apkConstant.getWerknemersPercentage() : BigDecimal.ZERO;
        return inhoudingPercentage.movePointLeft(SCHUIF_FACTOR_100);
    }

    @Override
    public BigDecimal getPatronaleBijdragePensioenVastbenoemdenApk(SleutelGegevens gegevens, LocalDate zoekDatum) {
        APKConstant2 apkConstant = apkConstant2Service.getByKey(gegevens.getPensioenStelsel(), zoekDatum);

        BigDecimal inhoudingPercentage = (apkConstant != null) ? apkConstant.getWerkgeversPercentage() : BigDecimal.ZERO;
        return inhoudingPercentage.movePointLeft(SCHUIF_FACTOR_100);
    }

    @Override
    public BigDecimal getInhoudingDubbelVakantiegeld(SleutelGegevens gegevens, LocalDate zoekDatum) {
        return constantManager.getByCodeDatum(Konstanten.KST_PCT_DVAK_INH_MAND, zoekDatum).getProcentFactor();
    }

    @Override
    public BigDecimal getInhoudingsPercentageDubbelVakantiegeldMandataris(SleutelGegevens gegevens, LocalDate zoekDatum) {
        DmfapplWnkengetal werknemersKengetal = gegevens.getWerknemersKengetal();
        Pensioenstelsel pensioenStelsel = gegevens.getPensioenStelsel();
        WerkgeversCategorie werkgeversCategorie = gegevens.getWerkgeversCategorie();

        DmfapplWnkengetal werknemersKengetalBijdrage;
        boolean isPensioenStelsel25Of26 = pensioenStelsel == Pensioenstelsel.KLASSIEK_STAATSREGIME || pensioenStelsel == Pensioenstelsel.POOL_DER_PARASTALEN;
        boolean isVastbenoemdMetPensioenStelsel25Of26 = werknemersKengetal == DmfapplWnkengetal.VASTBENOEMDE && isPensioenStelsel25Of26;
        if (werknemersKengetal == DmfapplWnkengetal.LOKALE_MANDATARIS_NIET_BECHERMD_DMFA
                || werknemersKengetal == DmfapplWnkengetal.LOKALE_MANDATARIS_BESCHERMD
                || isVastbenoemdMetPensioenStelsel25Of26) {
            werknemersKengetalBijdrage = DmfapplWnkengetal.EGALISATIEBIJDRAGE;
            return getInhoudingsPercentage(gegevens, zoekDatum, werknemersKengetalBijdrage, werkgeversCategorie);
        } else {
            return constantManager.getByCodeDatum(Konstanten.KST_PCT_DVAK_INH_MAND, zoekDatum).getProcentFactor();
        }
    }
}
